  1	import * as React from 'react';
  2	import ReactResizeDetector from 'react-resize-detector';
  3	import { Tab, Popover, PopoverPosition } from '@patternfly/react-core';
  4	import { ThProps, IRow } from '@patternfly/react-table';
  5	import { kialiStyle } from 'styles/StyleUtils';
  6	import { SimpleTabs } from 'components/Tab/SimpleTabs';
  7	import { PFColors } from 'components/Pf/PfColors';
  8	import { SimpleTable } from 'components/Table/SimpleTable';
  9	
 10	export interface MeshHelpFindProps {
 11	  children: React.ReactNode;
 12	  className?: string;
 13	  onClose: () => void;
 14	}
 15	
 16	const height = 'auto';
 17	const maxHeight = '34rem';
 18	const maxWidth = '37rem';
 19	const width = maxWidth;
 20	const contentWidth = '34.5rem';
 21	
 22	const tabFont: React.CSSProperties = {
 23	  fontSize: 'var(--kiali-global--font-size)'
 24	};
 25	
 26	const popoverStyle = kialiStyle({
 27	  height: height,
 28	  maxHeight: maxHeight,
 29	  maxWidth: maxWidth,
 30	  overflow: 'hidden',
 31	  overflowX: 'auto',
 32	  overflowY: 'auto',
 33	  width: width
 34	});
 35	
 36	const prefaceStyle = kialiStyle({
 37	  fontSize: '0.75rem',
 38	  color: PFColors.ColorLight100,
 39	  backgroundColor: PFColors.Blue600,
 40	  width: contentWidth,
 41	  height: '4rem',
 42	  padding: '0.25rem',
 43	  resize: 'none',
 44	  overflowY: 'hidden'
 45	});
 46	
 47	export const MeshHelpFind: React.FC<MeshHelpFindProps> = (props: MeshHelpFindProps) => {
 48	  // Incrementing mock counter to force a re-render in React hooks
 49	  const [, forceUpdate] = React.useReducer(x => x + 1, 0);
 50	
 51	  const onResize = (): void => {
 52	    forceUpdate();
 53	  };
 54	
 55	  const preface =
 56	    'You can use the Find and Hide fields to highlight or hide mesh nodes and edges. Each field accepts ' +
 57	    'expressions using the language described below. Preset expressions are available via the dropdown. ' +
 58	    'Hide takes precedence when using Find and Hide together.';
 59	
 60	  const edgeColumns: ThProps[] = [{ title: 'Expression' }, { title: 'Notes' }];
 61	
 62	  const edgeRows: IRow[] = [{ cells: ['N/A Currently no Edge expressions'] }];
 63	
 64	  const exampleColumns: ThProps[] = [{ title: 'Expression' }, { title: 'Description' }];
 65	
 66	  const exampleRows: IRow[] = [
 67	    {
 68	      cells: [
 69	        'label:region',
 70	        `nodes with the 'region' label. This tests for label existence, the label value is ignored.`
 71	      ]
 72	    },
 73	    {
 74	      cells: [
 75	        '!label:region',
 76	        `nodes without the 'region' label. This tests for label existence, the label value is ignored.`
 77	      ]
 78	    },
 79	    { cells: ['label:region = east', `nodes with 'region' label equal to 'east'`] },
 80	    {
 81	      cells: [
 82	        'label:region != east',
 83	        `nodes with 'region' label not equal to 'east'.  Note, "!label:region = east" is invalid, leading negation is valid only for label existence.`
 84	      ]
 85	    },
 86	    { cells: ['name = test-kiali', `nodes with infraName equal to 'test-kiali'`] },
 87	    { cells: ['name not contains test', `"nodes with infraName not containing 'test'`] },
 88	    { cells: ['name startswith test', `nodes with infraName starting with 'test'`] },
 89	    {
 90	      cells: [
 91	        'name != test-kiali and ns=test-ns',
 92	        `nodes with infraName not equal to 'test-kiali' and with namespace equal to 'test-ns'`
 93	      ]
 94	    },
 95	    {
 96	      cells: ['node = infra or name startswith test or !traffic', 'infra node or any node starting with "test"']
 97	    }
 98	  ];
 99	
100	  const nodeColumns: ThProps[] = [{ title: 'Expression' }, { title: 'Notes' }];
101	
102	  const nodeRows: IRow[] = [
103	    { cells: ['cluster <op> <clusterName>', 'nodes within the matching clusters'] },
104	    { cells: ['label:<label> <op> <value>', '<label> is a k8s label on the service, workload, etc'] },
105	    { cells: ['name <op> <string>', 'tests against infraName'] },
106	    { cells: ['namespace <op> <namespaceName>', 'nodes within the matching namespaces'] },
107	    { cells: ['type <op> <infraType>', 'infraType: dataplane | istiod | kiali | metricStore | traceStore'] },
108	    { cells: ['healthy', 'is not degraded or failing.'] }
109	  ];
110	
111	  const noteColumns: ThProps[] = [{ title: 'Usage Note', width: 10 }];
112	
113	  const noteRows: IRow[] = [
114	    { cells: ['Press Tab key to autocomplete operands.'] },
115	    { cells: ['OR has precedence over AND.  Parentheses are not supported.'] },
116	    { cells: ['Use OR to combine node and edge criteria.'] },
117	    { cells: [`Unary operands may optionally be prefixed with "is" or "has". (i.e. "is outofmesh")`] },
118	    { cells: ['Abbreviate: ns|namespace, ms|metricStore, ts|traceStore'] },
119	    { cells: ['Hiding nodes will automatically hide connected edges.'] },
120	    { cells: ['Hiding edges will automatically hide nodes left with no visible edges.'] },
121	    { cells: ['Hiding "healthy" nodes may still leave valid, healthy edges in the mesh.'] }
122	  ];
123	
124	  const operatorColumns: ThProps[] = [{ title: 'Operator' }, { title: 'Description' }];
125	
126	  const operatorRows: IRow[] = [
127	    { cells: ['! | not <unary expression>', `negation`] },
128	    { cells: ['=', `equals`] },
129	    { cells: ['!=', `not equals`] },
130	    { cells: ['endswith | $=', `ends with, strings only`] },
131	    { cells: ['!endswith | !$=', `not ends with, strings only`] },
132	    { cells: ['startswith | ^=', `starts with, strings only`] },
133	    { cells: ['!startswith | !^=', `not starts with, strings only`] },
134	    { cells: ['contains | *=', 'contains, strings only'] },
135	    { cells: ['!contains | !*=', 'not contains, strings only'] },
136	    { cells: ['>', `greater than`] },
137	    { cells: ['>=', `greater than or equals`] },
138	    { cells: ['<', `less than`] },
139	    { cells: ['<=', `less than or equals`] }
140	  ];
141	
142	  const getTable = (label: string, columns: ThProps[], rows: IRow[]): React.ReactNode => {
143	    return <SimpleTable label={label} columns={columns} rows={rows} />;
144	  };
145	
146	  const exampleTable = getTable('Example Table', exampleColumns, exampleRows);
147	  const nodeTable = getTable('Node Table', nodeColumns, nodeRows);
148	  const edgeTable = getTable('Edge Table', edgeColumns, edgeRows);
149	  const operatorTable = getTable('Operator Table', operatorColumns, operatorRows);
150	  const noteTable = getTable('Note Table', noteColumns, noteRows);
151	
152	  return (
153	    <>
154	      <ReactResizeDetector
155	        refreshMode="debounce"
156	        refreshRate={100}
157	        skipOnMount={true}
158	        handleWidth={true}
159	        handleHeight={true}
160	        onResize={onResize}
161	      />
162	
163	      <Popover
164	        data-test="mesh-find-hide-help"
165	        className={popoverStyle}
166	        position={PopoverPosition.auto}
167	        isVisible={true}
168	        hideOnOutsideClick={false}
169	        shouldClose={props.onClose}
170	        headerContent={
171	          <div>
172	            <span>Mesh Find/Hide</span>
173	          </div>
174	        }
175	        bodyContent={
176	          <>
177	            <textarea className={`${prefaceStyle}`} readOnly={true} value={preface} />
178	
179	            <SimpleTabs id="mesh_find_help_tabs" defaultTab={0} style={{ width: contentWidth }}>
180	              <Tab style={tabFont} eventKey={0} title="Examples">
181	                {exampleTable}
182	              </Tab>
183	
184	              <Tab style={tabFont} eventKey={1} title="Nodes">
185	                {nodeTable}
186	              </Tab>
187	
188	              <Tab style={tabFont} eventKey={2} title="Edges">
189	                {edgeTable}
190	              </Tab>
191	
192	              <Tab style={tabFont} eventKey={3} title="Operators">
193	                {operatorTable}
194	              </Tab>
195	
196	              <Tab style={tabFont} eventKey={4} title="Usage Notes">
197	                {noteTable}
198	              </Tab>
199	            </SimpleTabs>
200	          </>
201	        }
202	      >
203	        <>{props.children}</>
204	      </Popover>
205	    </>
206	  );
207	};

