 1	import * as React from 'react';
 2	import { Tabs, TabProps } from '@patternfly/react-core';
 3	
 4	// SimpleTabs is just a Tabs wrapper than encapsulates the activeTab state handling such
 5	// that parent components of Tabs don't have to re-render on a tab change.
 6	
 7	type SimpleTabsProps = {
 8	  children: React.ReactNode;
 9	  className?: string;
10	  defaultTab: number;
11	  id: string;
12	  isFilled?: boolean;
13	  mountOnEnter?: boolean;
14	  style?: React.CSSProperties;
15	  unmountOnExit?: boolean;
16	};
17	
18	export const SimpleTabs: React.FC<SimpleTabsProps> = (props: SimpleTabsProps) => {
19	  const [activeTab, setActiveTab] = React.useState<string | number>(props.defaultTab);
20	
21	  const handleTabSelect = (_event: React.MouseEvent, index: TabProps['eventKey']): void => {
22	    setActiveTab(index);
23	  };
24	
25	  return (
26	    <Tabs
27	      className={props.className}
28	      id={props.id}
29	      style={props.style ? props.style : {}}
30	      isFilled={props.isFilled ? props.isFilled : true}
31	      activeKey={activeTab}
32	      onSelect={handleTabSelect}
33	      mountOnEnter={props.mountOnEnter === undefined ? true : props.mountOnEnter}
34	      unmountOnExit={props.unmountOnExit === undefined ? true : props.unmountOnExit}
35	    >
36	      {!Array.isArray(props.children) ? <>{props.children}</> : props.children.map(child => child)}
37	    </Tabs>
38	  );
39	};

